} [MethodHook(typeof(app.GuiSaveLoadController.Unit), nameof(app.GuiSaveLoadController.Unit.onSetup), MethodHookType.Post)]
public static void OnSetupPost(ref ulong retval) { if (!initialized || pendingUnit == null) return; try { int current = pendingUnit._SaveItemNum; if (current < MAX_GAME_SAVES) { pendingUnit._SaveItemNum = MAX_GAME_SAVES; } } catch (Exception e) { API.LogWarning($"[AdditionalSaves] onSetup patch failed: {e.Message}"); } pendingUnit = null; // always clear
} How it works: Pre-hook receives Span<ulong> args. args[0] is the thread context, args[1] is this, args[2+] are the method parameters. Convert args[1] to a typed proxy and stash it in a static field. Return PreHookResult.Continue to let the original method execute (or PreHookResult.Skip to suppress it). Post-hook receives ref ulong retval. It reads the stashed reference, patches the object, then nulls the reference to avoid holding a stale pointer. Always null your stashed references in the post-hook. The managed object could be collected between frames if you hold onto it.

